B.RH=new A.a_("Supishi \u2014 Mission Form Digitization","Supishi \u2014 \u0627\u0644\u06a9\u062a\u0631\u0648\u0646\u06cc\u06a9\u06cc\u200c\u0633\u0627\u0632\u06cc \u0641\u0631\u0645 \u0645\u0623\u0645\u0648\u0631\u06cc\u062a")
B.R1=new A.a_("Django web platform digitizing field mission forms \u2014 multi-step approval workflow with SMS notifications and full reporting.","\u067e\u0644\u062a\u0641\u0631\u0645 \u0648\u0628 Django \u0628\u0631\u0627\u06cc \u062f\u06cc\u062c\u06cc\u062a\u0627\u0644\u06cc\u200c\u0633\u0627\u0632\u06cc \u0641\u0631\u0645 \u0645\u0623\u0645\u0648\u0631\u06cc\u062a \u2014 \u06af\u0631\u062f\u0634 \u062a\u0623\u06cc\u06cc\u062f \u0686\u0646\u062f\u0645\u0631\u062d\u0644\u0647\u200c\u0627\u06cc \u0628\u0627 SMS \u0648 \u06af\u0632\u0627\u0631\u0634\u200c\u06af\u06cc\u0631\u06cc \u06a9\u0627\u0645\u0644.")
B.RF=new A.a_("Business Web App","\u0633\u0627\u0645\u0627\u0646\u0647 \u0648\u0628 \u0633\u0627\u0632\u0645\u0627\u0646\u06cc")
B.T1=s(["Django","SMS API","Workflow","Reporting"],t.s)
B.Rp=new A.a_("A Django-powered web platform that replaces paper-based mission forms for field operations. When company staff go on missions and inspect client equipment, they fill out digital forms for each device and submit them. An SMS is automatically sent to the client company manager with the form details for review and approval. Once approved, the form moves to the support manager to register and confirm costs. Finally, the department manager reviews all information and, if correct, gives final approval and archives the form. The system includes comprehensive reporting on forms, missions, companies, submitters, and more.","\u067e\u0644\u062a\u0641\u0631\u0645 \u0648\u0628 Django \u06a9\u0647 \u0641\u0631\u0645\u200c\u0647\u0627\u06cc \u06a9\u0627\u063a\u0630\u06cc \u0645\u0623\u0645\u0648\u0631\u06cc\u062a \u0631\u0627 \u062f\u0631 \u0639\u0645\u0644\u06cc\u0627\u062a \u0645\u06cc\u062f\u0627\u0646\u06cc \u062c\u0627\u06cc\u06af\u0632\u06cc\u0646 \u0645\u06cc\u200c\u06a9\u0646\u062f. \u0648\u0642\u062a\u06cc \u0646\u06cc\u0631\u0648\u0647\u0627\u06cc \u0634\u0631\u06a9\u062a \u0645\u0623\u0645\u0648\u0631\u06cc\u062a \u0645\u06cc\u200c\u0631\u0648\u0646\u062f \u0648 \u062a\u062c\u0647\u06cc\u0632\u0627\u062a \u0645\u0634\u062a\u0631\u06cc \u0631\u0627 \u0628\u0627\u0632\u062f\u06cc\u062f \u0645\u06cc\u200c\u06a9\u0646\u0646\u062f\u060c \u0641\u0631\u0645 \u062f\u06cc\u062c\u06cc\u062a\u0627\u0644 \u0628\u0631\u0627\u06cc \u0647\u0631 \u062f\u0633\u062a\u06af\u0627\u0647 \u067e\u0631 \u0648 \u062b\u0628\u062a \u0645\u06cc\u200c\u06a9\u0646\u0646\u062f. \u067e\u06cc\u0627\u0645\u06a9 \u062e\u0648\u062f\u06a9\u0627\u0631 \u0628\u0647 \u0645\u0633\u0626\u0648\u0644 \u0634\u0631\u06a9\u062a \u0645\u0634\u062a\u0631\u06cc \u0628\u0627 \u062c\u0632\u0626\u06cc\u0627\u062a \u0641\u0631\u0645 \u0627\u0631\u0633\u0627\u0644 \u0645\u06cc\u200c\u0634\u0648\u062f \u062a\u0627 \u0628\u062e\u0648\u0627\u0646\u062f \u0648 \u062a\u0623\u06cc\u06cc\u062f \u06a9\u0646\u062f. \u067e\u0633 \u0627\u0632 \u062a\u0623\u06cc\u06cc\u062f\u060c \u0641\u0631\u0645 \u0628\u0647 \u0645\u0633\u0626\u0648\u0644 \u067e\u0634\u062a\u06cc\u0628\u0627\u0646\u06cc \u0645\u06cc\u200c\u0631\u0648\u062f \u062a\u0627 \u0647\u0632\u06cc\u0646\u0647\u200c\u0647\u0627 \u0631\u0627 \u062b\u0628\u062a \u0648 \u062a\u0623\u06cc\u06cc\u062f \u06a9\u0646\u062f. \u062f\u0631 \u0646\u0647\u0627\u06cc\u062a \u0645\u062f\u06cc\u0631 \u0628\u062e\u0634 \u0647\u0645\u0647 \u0627\u0637\u0644\u0627\u0639\u0627\u062a \u0631\u0627 \u0628\u0631\u0631\u0633\u06cc \u0648 \u062f\u0631 \u0635\u0648\u0631\u062a \u0635\u062d\u062a\u060c \u062a\u0623\u06cc\u06cc\u062f \u0646\u0647\u0627\u06cc\u06cc \u0648 \u0628\u0627\u06cc\u06af\u0627\u0646\u06cc \u0645\u06cc\u200c\u06a9\u0646\u062f. \u06af\u0632\u0627\u0631\u0634\u200c\u06af\u06cc\u0631\u06cc \u06a9\u0627\u0645\u0644 \u0627\u0632 \u0641\u0631\u0645\u200c\u0647\u0627\u060c \u0645\u0623\u0645\u0648\u0631\u06cc\u062a\u200c\u0647\u0627\u060c \u0634\u0631\u06a9\u062a\u200c\u0647\u0627\u060c \u062b\u0628\u062a\u200c\u06a9\u0646\u0646\u062f\u06af\u0627\u0646 \u0648 ... \u0648\u062c\u0648\u062f \u062f\u0627\u0631\u062f.")
B.Rt=new A.a_("Paper mission forms caused delays, lost documents, no audit trail, and a slow multi-party approval chain between field staff, client managers, support, and department heads.","\u0641\u0631\u0645\u200c\u0647\u0627\u06cc \u06a9\u0627\u063a\u0630\u06cc \u0645\u0623\u0645\u0648\u0631\u06cc\u062a \u0628\u0627\u0639\u062b \u062a\u0623\u062e\u06cc\u0631\u060c \u06af\u0645 \u0634\u062f\u0646 \u0645\u062f\u0627\u0631\u06a9\u060c \u0646\u0628\u0648\u062f audit trail \u0648 \u0632\u0646\u062c\u06cc\u0631\u0647 \u062a\u0623\u06cc\u06cc\u062f \u06a9\u0646\u062f \u0628\u06cc\u0646 \u0646\u06cc\u0631\u0648\u06cc \u0645\u06cc\u062f\u0627\u0646\u06cc\u060c \u0645\u062f\u06cc\u0631 \u0645\u0634\u062a\u0631\u06cc\u060c \u067e\u0634\u062a\u06cc\u0628\u0627\u0646\u06cc \u0648 \u0645\u062f\u06cc\u0631 \u0628\u062e\u0634 \u0645\u06cc\u200c\u0634\u062f.")
B.Sn=new A.a_("Built with Django \u2014 digital form submission per device during missions, automated SMS notifications to client managers, staged approval workflow (client \u2192 support costs \u2192 department manager \u2192 archive), role-based access, and rich reporting dashboards filtered by forms, missions, companies, and staff.","\u0628\u0627 Django \u2014 \u062b\u0628\u062a \u0641\u0631\u0645 \u062f\u06cc\u062c\u06cc\u062a\u0627\u0644 \u0628\u0631\u0627\u06cc \u0647\u0631 \u062f\u0633\u062a\u06af\u0627\u0647 \u062f\u0631 \u0645\u0623\u0645\u0648\u0631\u06cc\u062a\u060c \u0627\u0639\u0644\u0627\u0646 SMS \u062e\u0648\u062f\u06a9\u0627\u0631 \u0628\u0647 \u0645\u062f\u06cc\u0631 \u0645\u0634\u062a\u0631\u06cc\u060c \u06af\u0631\u062f\u0634 \u062a\u0623\u06cc\u06cc\u062f \u0645\u0631\u062d\u0644\u0647\u200c\u0627\u06cc (\u0645\u0634\u062a\u0631\u06cc \u2190 \u0647\u0632\u06cc\u0646\u0647 \u067e\u0634\u062a\u06cc\u0628\u0627\u0646\u06cc \u2190 \u0645\u062f\u06cc\u0631 \u0628\u062e\u0634 \u2190 \u0628\u0627\u06cc\u06af\u0627\u0646\u06cc)\u060c \u062f\u0633\u062a\u0631\u0633\u06cc \u0646\u0642\u0634\u200c\u0645\u062d\u0648\u0631 \u0648 \u062f\u0627\u0634\u0628\u0648\u0631\u062f \u06af\u0632\u0627\u0631\u0634 \u0628\u0631 \u0627\u0633\u0627\u0633 \u0641\u0631\u0645\u060c \u0645\u0623\u0645\u0648\u0631\u06cc\u062a\u060c \u0634\u0631\u06a9\u062a \u0648 \u067e\u0631\u0633\u0646\u0644.")
B.Rw=new A.a_("Paperless mission documentation, faster approvals via SMS-triggered client sign-off, traceable workflow at every stage, and complete analytics for operations management.","\u0645\u0633\u062a\u0646\u062f\u0633\u0627\u0632\u06cc \u0628\u062f\u0648\u0646 \u06a9\u0627\u063a\u0630 \u0645\u0623\u0645\u0648\u0631\u06cc\u062a\u060c \u062a\u0623\u06cc\u06cc\u062f \u0633\u0631\u06cc\u0639\u200c\u062a\u0631 \u0628\u0627 SMS \u0645\u0634\u062a\u0631\u06cc\u060c \u06af\u0631\u062f\u0634 \u06a9\u0627\u0631 \u0642\u0627\u0628\u0644 \u0631\u062f\u06cc\u0627\u0628\u06cc \u062f\u0631 \u0647\u0631 \u0645\u0631\u062d\u0644\u0647\u060c \u0648 \u0622\u0645\u0627\u0631 \u06a9\u0627\u0645\u0644 \u0628\u0631\u0627\u06cc \u0645\u062f\u06cc\u0631\u06cc\u062a \u0639\u0645\u0644\u06cc\u0627\u062a.")
