B.Ru=new A.a_("Developer Portfolio Website","\u0648\u0628\u200c\u0633\u0627\u06cc\u062a \u067e\u0648\u0631\u062a\u0641\u0648\u0644\u06cc\u0648 \u0634\u062e\u0635\u06cc")
B.R3=new A.a_("Bilingual Flutter web portfolio \u2014 project case studies, skills, experience, education, and contact in EN/FA with RTL support.","\u067e\u0648\u0631\u062a\u0641\u0648\u0644\u06cc\u0648 \u0648\u0628 Flutter \u062f\u0648\u0632\u0628\u0627\u0646\u0647 \u2014 case study \u067e\u0631\u0648\u0698\u0647\u200c\u0647\u0627\u060c \u0645\u0647\u0627\u0631\u062a\u200c\u0647\u0627\u060c \u062a\u062c\u0631\u0628\u0647\u060c \u062a\u062d\u0635\u06cc\u0644\u0627\u062a \u0648 \u062a\u0645\u0627\u0633 \u0628\u0647 \u0641\u0627\u0631\u0633\u06cc \u0648 \u0627\u0646\u06af\u0644\u06cc\u0633\u06cc \u0628\u0627 \u067e\u0634\u062a\u06cc\u0628\u0627\u0646\u06cc RTL.")
