B.Sv=new A.a_("Django REST API + Electron desktop app for multi-warehouse inventory \u2014 role-based access, barcode/Excel intake, and rich reporting.","REST API \u062c\u0646\u06af\u0648 + \u0627\u067e \u062f\u0633\u06a9\u062a\u0627\u067e Electron \u0628\u0631\u0627\u06cc \u0645\u0648\u062c\u0648\u062f\u06cc \u0686\u0646\u062f\u0627\u0646\u0628\u0627\u0631\u0647 \u2014 \u062f\u0633\u062a\u0631\u0633\u06cc \u0646\u0642\u0634\u200c\u0645\u062d\u0648\u0631\u060c \u0648\u0631\u0648\u062f \u0628\u0627 \u0628\u0627\u0631\u06a9\u062f/\u0627\u06a9\u0633\u0644 \u0648 \u06af\u0632\u0627\u0631\u0634\u200c\u06af\u06cc\u0631\u06cc.")
