B.Sz=new A.a_("RamODis \u2014 Digital Board Game","\u0628\u0627\u0632\u06cc \u0631\u0627\u0645 \u0648 \u062f\u06cc\u0633 \u2014 \u067e\u06cc\u0627\u062f\u0647\u200c\u0633\u0627\u0632\u06cc \u062f\u06cc\u062c\u06cc\u062a\u0627\u0644")
B.Rg=new A.a_("Flutter implementation of RamODis \u2014 standalone local multiplayer or online play via Django REST Framework backend.","\u067e\u06cc\u0627\u062f\u0647\u200c\u0633\u0627\u0632\u06cc Flutter \u0628\u0627\u0632\u06cc \u0631\u0627\u0645 \u0648 \u062f\u06cc\u0633 \u2014 multiplayer \u0645\u062d\u0644\u06cc standalone \u06cc\u0627 \u0622\u0646\u0644\u0627\u06cc\u0646 \u0628\u0627 \u0628\u06a9\u200c\u0627\u0646\u062f Django REST Framework.")
B.SB=new A.a_("Mobile Game","\u0628\u0627\u0632\u06cc \u0645\u0648\u0628\u0627\u06cc\u0644")
B.a0D=s(["Flutter","Django REST","Local Network","Multiplayer"],t.s)
B.kh=new A.z(1,0.9607843137254902,0.6196078431372549,0.043137254901960784,B.i)
B.Sl=new A.a_("A digital adaptation of RamODis, delivered in two architectures. Version 1 is fully built with Flutter \u2014 players can compete against an AI bot or friends over a local network. Version 2 uses Flutter for the frontend and Django REST Framework for the backend, enabling bot matches and friend-vs-friend games over a wider network beyond local LAN. Both versions preserve core game rules while adding smooth UI, turn management, and real-time multiplayer sync.","\u0646\u0633\u062e\u0647 \u062f\u06cc\u062c\u06cc\u062a\u0627\u0644 \u0628\u0627\u0632\u06cc \u06a9\u0644\u0627\u0633\u06cc\u06a9 \u0631\u0627\u0645 \u0648 \u062f\u06cc\u0633 \u062f\u0631 \u062f\u0648 \u0645\u0639\u0645\u0627\u0631\u06cc. \u0646\u0633\u062e\u0647 \u06f1 \u06a9\u0627\u0645\u0644\u0627\u064b Flutter \u2014 \u0628\u0627\u0632\u06cc \u0628\u0627 \u0631\u0628\u0627\u062a AI \u06cc\u0627 \u062f\u0648\u0633\u062a\u0627\u0646 \u0631\u0648\u06cc \u0634\u0628\u06a9\u0647 \u0645\u062d\u0644\u06cc. \u0646\u0633\u062e\u0647 \u06f2 \u0641\u0631\u0627\u0646\u062a Flutter \u0648 \u0628\u06a9\u200c\u0627\u0646\u062f Django REST Framework \u2014 \u0628\u0627\u0632\u06cc \u0628\u0627 \u0631\u0628\u0627\u062a \u0648 \u062f\u0648\u0633\u062a\u0627\u0646 \u0631\u0648\u06cc \u0634\u0628\u06a9\u0647 \u06af\u0633\u062a\u0631\u062f\u0647\u200c\u062a\u0631 \u0627\u0632 LAN. \u0647\u0631 \u062f\u0648 \u0646\u0633\u062e\u0647 \u0642\u0648\u0627\u0646\u06cc\u0646 \u0627\u0635\u0644\u06cc \u0628\u0627\u0632\u06cc \u0631\u0627 \u062d\u0641\u0638 \u0648 UI \u0631\u0648\u0627\u0646\u060c \u0645\u062f\u06cc\u0631\u06cc\u062a \u0646\u0648\u0628\u062a \u0648 \u0647\u0645\u06af\u0627\u0645\u200c\u0633\u0627\u0632\u06cc multiplayer \u0631\u0627 \u0627\u0636\u0627\u0641\u0647 \u0645\u06cc\u200c\u06a9\u0646\u0646\u062f.")
B.R5=new A.a_("The traditional board game needed a digital version that feels natural on mobile \u2014 with reliable multiplayer whether players are in the same room (local) or connecting remotely (online).","\u0628\u0627\u0632\u06cc \u0633\u0646\u062a\u06cc \u0628\u0647 \u0646\u0633\u062e\u0647 \u062f\u06cc\u062c\u06cc\u062a\u0627\u0644 \u0637\u0628\u06cc\u0639\u06cc \u0631\u0648\u06cc \u0645\u0648\u0628\u0627\u06cc\u0644 \u0646\u06cc\u0627\u0632 \u062f\u0627\u0634\u062a \u2014 \u0628\u0627 multiplayer \u067e\u0627\u06cc\u062f\u0627\u0631 \u0686\u0647 \u062f\u0631 \u06cc\u06a9 \u0627\u062a\u0627\u0642 (\u0645\u062d\u0644\u06cc) \u0648 \u0686\u0647 \u0627\u0632 \u0631\u0627\u0647 \u062f\u0648\u0631 (\u0622\u0646\u0644\u0627\u06cc\u0646).")
B.RD=new A.a_("Built Version 1 entirely in Flutter with local network discovery for nearby friends and an AI bot opponent. Built Version 2 with Flutter client + Django DRF backend for scalable online matchmaking, game state sync, and remote friend play \u2014 giving users flexibility between offline-local and cloud-connected modes.","\u0646\u0633\u062e\u0647 \u06f1 \u06a9\u0627\u0645\u0644\u0627\u064b Flutter \u0628\u0627 \u06a9\u0634\u0641 \u0634\u0628\u06a9\u0647 \u0645\u062d\u0644\u06cc \u0628\u0631\u0627\u06cc \u062f\u0648\u0633\u062a\u0627\u0646 \u0646\u0632\u062f\u06cc\u06a9 \u0648 \u0631\u0628\u0627\u062a AI. \u0646\u0633\u062e\u0647 \u06f2 \u06a9\u0644\u0627\u06cc\u0646\u062a Flutter + Django DRF \u0628\u0631\u0627\u06cc matchmaking \u0622\u0646\u0644\u0627\u06cc\u0646\u060c \u0647\u0645\u06af\u0627\u0645\u200c\u0633\u0627\u0632\u06cc state \u0628\u0627\u0632\u06cc \u0648 \u0628\u0627\u0632\u06cc \u0627\u0632 \u0631\u0627\u0647 \u062f\u0648\u0631 \u2014 \u0627\u0646\u0639\u0637\u0627\u0641 \u0628\u06cc\u0646 \u062d\u0627\u0644\u062a \u0645\u062d\u0644\u06cc offline \u0648 \u0645\u062a\u0635\u0644 \u0628\u0647 cloud.")
B.RR=new A.a_("Two production-ready game modes \u2014 quick local sessions with friends and scalable online play \u2014 bringing a beloved board game to mobile with modern UX.","\u062f\u0648 \u062d\u0627\u0644\u062a \u0628\u0627\u0632\u06cc \u0622\u0645\u0627\u062f\u0647 \u2014 \u062c\u0644\u0633\u0627\u062a \u0633\u0631\u06cc\u0639 \u0645\u062d\u0644\u06cc \u0628\u0627 \u062f\u0648\u0633\u062a\u0627\u0646 \u0648 \u0628\u0627\u0632\u06cc \u0622\u0646\u0644\u0627\u06cc\u0646 \u0645\u0642\u06cc\u0627\u0633\u200c\u067e\u0630\u06cc\u0631 \u2014 \u0622\u0648\u0631\u062f\u0646 \u0628\u0627\u0632\u06cc \u0645\u062d\u0628\u0648\u0628 \u0628\u0647 \u0645\u0648\u0628\u0627\u06cc\u0644 \u0628\u0627 UX \u0645\u062f\u0631\u0646.")
