B.N5=new A.z(1,0.9254901960784314,0.2823529411764706,0.6,B.i)
B.QU=new A.a_("A Flutter music player that scans and lists all songs on the device, sortable by date or name. Users can play tracks sequentially or in shuffle mode. Configurable filters exclude songs shorter than a set duration or below a minimum file size from the library and playback. Full playlist creation, favorite marking, and a built-in equalizer for custom audio tuning round out the experience.","\u0645\u0648\u0632\u06cc\u06a9 \u067e\u0644\u06cc\u0631 Flutter \u06a9\u0647 \u0622\u0647\u0646\u06af\u200c\u0647\u0627\u06cc \u062f\u0633\u062a\u06af\u0627\u0647 \u0631\u0627 \u0627\u0633\u06a9\u0646 \u0648 \u0644\u06cc\u0633\u062a \u0645\u06cc\u200c\u06a9\u0646\u062f \u2014 \u0645\u0631\u062a\u0628\u200c\u0633\u0627\u0632\u06cc \u0628\u0631 \u0627\u0633\u0627\u0633 \u0632\u0645\u0627\u0646 \u06cc\u0627 \u0646\u0627\u0645. \u067e\u062e\u0634 \u062a\u0631\u062a\u06cc\u0628\u06cc \u06cc\u0627 \u062a\u0635\u0627\u062f\u0641\u06cc (shuffle). \u0641\u06cc\u0644\u062a\u0631 \u0642\u0627\u0628\u0644 \u062a\u0646\u0638\u06cc\u0645: \u062d\u0630\u0641 \u0622\u0647\u0646\u06af\u200c\u0647\u0627\u06cc \u06a9\u0648\u062a\u0627\u0647\u200c\u062a\u0631 \u0627\u0632 m \u062f\u0642\u06cc\u0642\u0647 \u06cc\u0627 \u06a9\u0648\u0686\u06a9\u200c\u062a\u0631 \u0627\u0632 n \u062d\u062c\u0645 \u0627\u0632 \u0644\u06cc\u0633\u062a \u0648 \u067e\u062e\u0634. \u0633\u0627\u062e\u062a \u067e\u0644\u06cc\u200c\u0644\u06cc\u0633\u062a\u060c favorite \u06a9\u0631\u062f\u0646 \u0622\u0647\u0646\u06af\u200c\u0647\u0627 \u0648 \u0627\u06a9\u0648\u0644\u0627\u06cc\u0632\u0631 \u062f\u0627\u062e\u0644\u06cc \u0628\u0631\u0627\u06cc \u062a\u0646\u0638\u06cc\u0645 \u0635\u062f\u0627.")
B.S9=new A.a_("Default mobile music apps often lack fine-grained control \u2014 filtering short clips and small files, custom playlists, favorites, and equalizer settings in one lightweight local player.","\u0627\u067e\u200c\u0647\u0627\u06cc \u067e\u06cc\u0634\u200c\u0641\u0631\u0636 \u0645\u0648\u0633\u06cc\u0642\u06cc \u0645\u0648\u0628\u0627\u06cc\u0644 \u06a9\u0646\u062a\u0631\u0644 \u062f\u0642\u06cc\u0642 \u0646\u062f\u0627\u0631\u0646\u062f \u2014 \u0641\u06cc\u0644\u062a\u0631 \u06a9\u0644\u06cc\u067e \u06a9\u0648\u062a\u0627\u0647 \u0648 \u0641\u0627\u06cc\u0644 \u06a9\u0648\u0686\u06a9\u060c \u067e\u0644\u06cc\u200c\u0644\u06cc\u0633\u062a \u0633\u0641\u0627\u0631\u0634\u06cc\u060c favorite \u0648 \u0627\u06a9\u0648\u0644\u0627\u06cc\u0632\u0631 \u062f\u0631 \u06cc\u06a9 \u067e\u062e\u0634\u200c\u06a9\u0646\u0646\u062f\u0647 \u0633\u0628\u06a9 \u0645\u062d\u0644\u06cc.")
B.SC=new A.a_("Built with Flutter \u2014 device media library integration, sort by name or date, sequential and shuffle playback, threshold filters for minimum duration and file size, playlist CRUD, favorites system, and native-style equalizer presets and custom bands.","\u0628\u0627 Flutter \u2014 \u0627\u062a\u0635\u0627\u0644 \u0628\u0647 \u06a9\u062a\u0627\u0628\u062e\u0627\u0646\u0647 \u0645\u062f\u06cc\u0627 \u062f\u0633\u062a\u06af\u0627\u0647\u060c \u0645\u0631\u062a\u0628\u200c\u0633\u0627\u0632\u06cc \u0646\u0627\u0645/\u0632\u0645\u0627\u0646\u060c \u067e\u062e\u0634 \u062a\u0631\u062a\u06cc\u0628\u06cc \u0648 shuffle\u060c \u0641\u06cc\u0644\u062a\u0631 \u062d\u062f\u0627\u0642\u0644 \u0645\u062f\u062a \u0648 \u062d\u062c\u0645 \u0641\u0627\u06cc\u0644\u060c CRUD \u067e\u0644\u06cc\u200c\u0644\u06cc\u0633\u062a\u060c \u0633\u06cc\u0633\u062a\u0645 \u0639\u0644\u0627\u0642\u0647\u200c\u0645\u0646\u062f\u06cc \u0648 preset \u0648 band \u0633\u0641\u0627\u0631\u0634\u06cc \u0627\u06a9\u0648\u0644\u0627\u06cc\u0632\u0631.")
B.S_=new A.a_("A polished offline music experience with smart library management, personal playlists, and full audio customization \u2014 no streaming dependency required.","\u062a\u062c\u0631\u0628\u0647 \u0645\u0648\u0633\u06cc\u0642\u06cc offline \u0628\u0627 \u0645\u062f\u06cc\u0631\u06cc\u062a \u0647\u0648\u0634\u0645\u0646\u062f \u06a9\u062a\u0627\u0628\u062e\u0627\u0646\u0647\u060c \u067e\u0644\u06cc\u200c\u0644\u06cc\u0633\u062a \u0634\u062e\u0635\u06cc \u0648 \u0633\u0641\u0627\u0631\u0634\u06cc\u200c\u0633\u0627\u0632\u06cc \u06a9\u0627\u0645\u0644 \u0635\u062f\u0627 \u2014 \u0628\u062f\u0648\u0646 \u0648\u0627\u0628\u0633\u062a\u06af\u06cc \u0628\u0647 streaming.")
B.pB=new A.a_("Flutter Developer","\u062a\u0648\u0633\u0639\u0647\u200c\u062f\u0647\u0646\u062f\u0647 Flutter")
B.X8=s(["assets/images/projects/music_player2.jpg"],t.s)
B.a70=new A.di("flutter-music-player",B.Rs,B.RK,B.Su,B.VH,B.N5,"",B.QU,B.S9,B.SC,B.S_,B.pB,B.pA,"assets/images/projects/music_player1.jpg",B.X8,!0)
B.RV=new A.a_("Online Clinic Appointment Booking","\u0633\u0627\u0645\u0627\u0646\u0647 \u0646\u0648\u0628\u062a\u200c\u062f\u0647\u06cc \u0622\u0646\u0644\u0627\u06cc\u0646 \u06a9\u0644\u06cc\u0646\u06cc\u06a9")
B.Rk=new A.a_("Django web app for clinics \u2014 managers publish available slots, patients book appointments online.","\u0648\u0628\u200c\u0627\u067e Django \u0628\u0631\u0627\u06cc \u06a9\u0644\u06cc\u0646\u06cc\u06a9 \u2014 \u0645\u062f\u06cc\u0631 \u0627\u0633\u0644\u0627\u062a\u200c\u0647\u0627\u06cc \u062e\u0627\u0644\u06cc \u0631\u0627 \u062a\u0639\u0631\u06cc\u0641 \u0645\u06cc\u200c\u06a9\u0646\u062f\u060c \u0628\u06cc\u0645\u0627\u0631\u0627\u0646 \u0622\u0646\u0644\u0627\u06cc\u0646 \u0631\u0632\u0631\u0648 \u0645\u06cc\u200c\u06a9\u0646\u0646\u062f.")
B.RA=new A.a_("Healthcare Web App","\u0633\u0627\u0645\u0627\u0646\u0647 \u0648\u0628 \u062f\u0631\u0645\u0627\u0646\u06cc")
B.Vs=s(["Django","Booking","Scheduling","MySQL"],t.s)
B.QZ=new A.a_("A Django-based online appointment scheduling platform for clinics. Clinic administrators define their available time slots on the website, and patients browse open appointments and reserve the time that suits them \u2014 replacing phone-based booking with a self-service digital flow.","\u067e\u0644\u062a\u0641\u0631\u0645 \u0631\u0632\u0631\u0648 \u0646\u0648\u0628\u062a \u0622\u0646\u0644\u0627\u06cc\u0646 \u0645\u0628\u062a\u0646\u06cc \u0628\u0631 Django \u0628\u0631\u0627\u06cc \u06a9\u0644\u06cc\u0646\u06cc\u06a9\u200c\u0647\u0627. \u0645\u0633\u0626\u0648\u0644 \u06a9\u0644\u06cc\u0646\u06cc\u06a9 \u0646\u0648\u0628\u062a\u200c\u0647\u0627\u06cc \u062e\u0627\u0644\u06cc \u0631\u0627 \u062f\u0631 \u0633\u0627\u06cc\u062a \u062a\u0639\u06cc\u06cc\u0646 \u0645\u06cc\u200c\u06a9\u0646\u062f \u0648 \u0645\u0634\u062a\u0631\u06cc\u0627\u0646/\u0628\u06cc\u0645\u0627\u0631\u0627\u0646 \u0628\u0627 \u062a\u0648\u062c\u0647 \u0628\u0647 \u0632\u0645\u0627\u0646\u200c\u0647\u0627\u06cc \u0622\u0632\u0627\u062f\u060c \u0647\u0631 \u062a\u0627\u06cc\u0645\u06cc \u06a9\u0647 \u0628\u062e\u0648\u0627\u0647\u0646\u062f \u0631\u0632\u0631\u0648 \u0645\u06cc\u200c\u06a9\u0646\u0646\u062f \u2014 \u062c\u0627\u06cc\u06af\u0632\u06cc\u0646 \u0646\u0648\u0628\u062a\u200c\u06af\u06cc\u0631\u06cc \u062a\u0644\u0641\u0646\u06cc \u0628\u0627 \u062c\u0631\u06cc\u0627\u0646 \u062f\u06cc\u062c\u06cc\u062a\u0627\u0644 self-service.")
B.RB=new A.a_("Phone-only appointment booking caused double bookings, staff overhead, and patients unable to see real-time availability outside business hours.","\u0646\u0648\u0628\u062a\u200c\u06af\u06cc\u0631\u06cc \u0641\u0642\u0637 \u062a\u0644\u0641\u0646\u06cc \u0628\u0627\u0639\u062b \u0631\u0632\u0631\u0648 \u062a\u06a9\u0631\u0627\u0631\u06cc\u060c \u0628\u0627\u0631 \u06a9\u0627\u0631\u06cc \u067e\u0631\u0633\u0646\u0644 \u0648 \u0646\u0627\u062a\u0648\u0627\u0646\u06cc \u0628\u06cc\u0645\u0627\u0631\u0627\u0646 \u062f\u0631 \u062f\u06cc\u062f\u0646 \u0632\u0645\u0627\u0646\u200c\u0647\u0627\u06cc \u0622\u0632\u0627\u062f \u062e\u0627\u0631\u062c \u0627\u0632 \u0633\u0627\u0639\u0627\u062a \u06a9\u0627\u0631\u06cc \u0645\u06cc\u200c\u0634\u062f.")
B.RZ=new A.a_("Built with Django \u2014 admin panel for clinic managers to create and manage available slots, public booking interface for patients to view open times and confirm reservations, with slot locking to prevent conflicts.","\u0628\u0627 Django \u2014 \u067e\u0646\u0644 \u0645\u062f\u06cc\u0631\u06cc\u062a \u0628\u0631\u0627\u06cc \u062a\u0639\u0631\u06cc\u0641 \u0648 \u0645\u062f\u06cc\u0631\u06cc\u062a \u0627\u0633\u0644\u0627\u062a\u200c\u0647\u0627\u06cc \u062e\u0627\u0644\u06cc\u060c \u0631\u0627\u0628\u0637 \u0639\u0645\u0648\u0645\u06cc \u0628\u0631\u0627\u06cc \u0645\u0634\u0627\u0647\u062f\u0647 \u0632\u0645\u0627\u0646\u200c\u0647\u0627\u06cc \u0622\u0632\u0627\u062f \u0648 \u062a\u0623\u06cc\u06cc\u062f \u0631\u0632\u0631\u0648\u060c \u0628\u0627 \u0642\u0641\u0644 \u0627\u0633\u0644\u0627\u062a \u0628\u0631\u0627\u06cc \u062c\u0644\u0648\u06af\u06cc\u0631\u06cc \u0627\u0632 \u062a\u062f\u0627\u062e\u0644.")
B.R6=new A.a_("Streamlined clinic scheduling, reduced phone load, 24/7 self-service booking for patients, and clear visibility of available appointments.","\u0632\u0645\u0627\u0646\u200c\u0628\u0646\u062f\u06cc \u0631\u0648\u0627\u0646 \u06a9\u0644\u06cc\u0646\u06cc\u06a9\u060c \u06a9\u0627\u0647\u0634 \u062a\u0645\u0627\u0633 \u062a\u0644\u0641\u0646\u06cc\u060c \u0631\u0632\u0631\u0648 self-service \u06f2\u06f4/\u06f7 \u0628\u0631\u0627\u06cc \u0628\u06cc\u0645\u0627\u0631\u0627\u0646 \u0648 \u062f\u06cc\u062f \u0634\u0641\u0627\u0641 \u0646\u0648\u0628\u062a\u200c\u0647\u0627\u06cc \u062e\u0627\u0644\u06cc.")
B.pz=new A.a_("Client project","\u067e\u0631\u0648\u0698\u0647 \u0645\u0634\u062a\u0631\u06cc")
B.a6Y=new A.di("clinic-appointment-booking",B.RV,B.Rk,B.RA,B.Vs,B.cv,"",B.QZ,B.RB,B.RZ,B.R6,B.eW,B.pz,"assets/images/projects/clinic-booking.jpg",B.bY,!1)
B.Se=new A.a_("IoT Tracker & Alarm Control App","\u0627\u067e \u06a9\u0646\u062a\u0631\u0644 \u0631\u062f\u06cc\u0627\u0628 \u0648 \u062f\u0632\u062f\u06af\u06cc\u0631 IoT")
B.St=new A.a_("Ionic frontend for an IoT platform \u2014 device pairing, remote configuration, tracking alerts via push notifications.","\u0641\u0631\u0627\u0646\u062a Ionic \u0628\u0631\u0627\u06cc \u067e\u0644\u062a\u0641\u0631\u0645 IoT \u2014 \u0627\u062a\u0635\u0627\u0644 \u062f\u0633\u062a\u06af\u0627\u0647\u060c \u062a\u0646\u0638\u06cc\u0645\u0627\u062a \u0627\u0632 \u0631\u0627\u0647 \u062f\u0648\u0631\u060c \u0647\u0634\u062f\u0627\u0631 \u0631\u062f\u06cc\u0627\u0628\u06cc \u0628\u0627 push notification.")
B.Rz=new A.a_("IoT Mobile App","\u0627\u067e \u0645\u0648\u0628\u0627\u06cc\u0644 IoT")
B.Yf=s(["Ionic","IoT","Push Notifications","TypeScript"],t.s)
B.MC=new A.z(1,0.23137254901960785,0.5098039215686274,0.9647058823529412,B.i)
B.RP=new A.a_("Frontend mobile application built with Ionic for an IoT security platform focused on alarm systems and GPS trackers. Users register devices in the app, connect to them over the network, and apply remote configuration settings. When a device detects a tracked event or trigger, it sends data to the backend server, which forwards real-time push notifications to the user's phone.","\u0627\u067e \u0645\u0648\u0628\u0627\u06cc\u0644 Ionic \u0628\u0631\u0627\u06cc \u067e\u0644\u062a\u0641\u0631\u0645 IoT \u0627\u0645\u0646\u06cc\u062a\u06cc \u2014 \u062f\u0632\u062f\u06af\u06cc\u0631 \u0648 \u0631\u062f\u06cc\u0627\u0628 GPS. \u06a9\u0627\u0631\u0628\u0631\u0627\u0646 \u062f\u0633\u062a\u06af\u0627\u0647\u200c\u0647\u0627 \u0631\u0627 \u062f\u0631 \u0627\u067e \u062a\u0639\u0631\u06cc\u0641\u060c \u0628\u0647 \u0622\u0646\u200c\u0647\u0627 \u0645\u062a\u0635\u0644 \u0648 \u062a\u0646\u0638\u06cc\u0645\u0627\u062a \u0627\u0632 \u0631\u0627\u0647 \u062f\u0648\u0631 \u0627\u0639\u0645\u0627\u0644 \u0645\u06cc\u200c\u06a9\u0646\u0646\u062f. \u0648\u0642\u062a\u06cc \u062f\u0633\u062a\u06af\u0627\u0647 \u0631\u0648\u06cc\u062f\u0627\u062f \u06cc\u0627 trigger \u0631\u062f\u06cc\u0627\u0628\u06cc \u0631\u0627 \u062a\u0634\u062e\u06cc\u0635 \u062f\u0647\u062f\u060c \u062f\u0627\u062f\u0647 \u0628\u0647 \u0633\u0631\u0648\u0631 \u0627\u0631\u0633\u0627\u0644 \u0648 \u0633\u0631\u0648\u0631 push notification \u0644\u062d\u0638\u0647\u200c\u0627\u06cc \u0628\u0647 \u0645\u0648\u0628\u0627\u06cc\u0644 \u06a9\u0627\u0631\u0628\u0631 \u0645\u06cc\u200c\u0641\u0631\u0633\u062a\u062f.")
B.S5=new A.a_("IoT device management required a cross-platform mobile UI for pairing, live configuration, and instant alerts \u2014 without users needing technical knowledge of each tracker or alarm model.","\u0645\u062f\u06cc\u0631\u06cc\u062a \u062f\u0633\u062a\u06af\u0627\u0647 IoT \u0628\u0647 UI \u0645\u0648\u0628\u0627\u06cc\u0644 cross-platform \u0628\u0631\u0627\u06cc pairing\u060c \u062a\u0646\u0638\u06cc\u0645\u0627\u062a live \u0648 \u0647\u0634\u062f\u0627\u0631 \u0641\u0648\u0631\u06cc \u0646\u06cc\u0627\u0632 \u062f\u0627\u0634\u062a \u2014 \u0628\u062f\u0648\u0646 \u062f\u0627\u0646\u0634 \u0641\u0646\u06cc \u06a9\u0627\u0631\u0628\u0631 \u0627\u0632 \u0647\u0631 \u0645\u062f\u0644 \u0631\u062f\u06cc\u0627\u0628 \u06cc\u0627 \u062f\u0632\u062f\u06af\u06cc\u0631.")
B.Ro=new A.a_("Built the frontend with Ionic \u2014 device registration and connection flows, remote settings panels per device type, real-time sync with backend API, and push notification integration so users are instantly notified when tracking events occur.","\u0641\u0631\u0627\u0646\u062a \u0628\u0627 Ionic \u2014 \u06af\u0631\u062f\u0634 \u062b\u0628\u062a \u0648 \u0627\u062a\u0635\u0627\u0644 \u062f\u0633\u062a\u06af\u0627\u0647\u060c \u067e\u0646\u0644 \u062a\u0646\u0638\u06cc\u0645\u0627\u062a \u0627\u0632 \u0631\u0627\u0647 \u062f\u0648\u0631 \u0628\u0631\u0627\u06cc \u0647\u0631 \u0646\u0648\u0639 \u062f\u0633\u062a\u06af\u0627\u0647\u060c \u0647\u0645\u06af\u0627\u0645\u200c\u0633\u0627\u0632\u06cc \u0644\u062d\u0638\u0647\u200c\u0627\u06cc \u0628\u0627 API \u0628\u06a9\u200c\u0627\u0646\u062f \u0648 \u06cc\u06a9\u067e\u0627\u0631\u0686\u0647\u200c\u0633\u0627\u0632\u06cc push notification \u0628\u0631\u0627\u06cc \u0627\u0639\u0644\u0627\u0646 \u0641\u0648\u0631\u06cc \u0631\u0648\u06cc\u062f\u0627\u062f\u0647\u0627\u06cc \u0631\u062f\u06cc\u0627\u0628\u06cc.")
B.SK=new A.a_("Unified mobile control for alarms and trackers, remote device management from anywhere, and immediate push alerts when events are detected.","\u06a9\u0646\u062a\u0631\u0644 \u06cc\u06a9\u067e\u0627\u0631\u0686\u0647 \u0645\u0648\u0628\u0627\u06cc\u0644 \u062f\u0632\u062f\u06af\u06cc\u0631 \u0648 \u0631\u062f\u06cc\u0627\u0628\u060c \u0645\u062f\u06cc\u0631\u06cc\u062a \u0627\u0632 \u0631\u0627\u0647 \u062f\u0648\u0631 \u062f\u0633\u062a\u06af\u0627\u0647 \u0627\u0632 \u0647\u0631 \u062c\u0627\u060c \u0648 \u0647\u0634\u062f\u0627\u0631 push \u0641\u0648\u0631\u06cc \u0647\u0646\u06af\u0627\u0645 \u062a\u0634\u062e\u06cc\u0635 \u0631\u0648\u06cc\u062f\u0627\u062f.")
B.S2=new A.a_("Frontend Developer","\u062a\u0648\u0633\u0639\u0647\u200c\u062f\u0647\u0646\u062f\u0647 \u0641\u0631\u0627\u0646\u062a\u200c\u0627\u0646\u062f")
B.a6V=new A.di("iot-tracker-ionic",B.Se,B.St,B.Rz,B.Yf,B.MC,"",B.RP,B.S5,B.Ro,B.SK,B.S2,B.pz,"assets/images/projects/IOTTracker1.png",B.bY,!1)
B.Sw=new A.a_("Gifted Students Admission Portal","\u0633\u0627\u0645\u0627\u0646\u0647 \u067e\u0630\u06cc\u0631\u0634 \u0627\u0633\u062a\u0639\u062f\u0627\u062f\u0647\u0627\u06cc \u062f\u0631\u062e\u0634\u0627\u0646")
B.RJ=new A.a_("Master's thesis project \u2014 Django DRF + React portal for managing gifted student applications at MSc and PhD levels.","\u067e\u0631\u0648\u0698\u0647 \u06a9\u0627\u0631\u0634\u0646\u0627\u0633\u06cc \u0627\u0631\u0634\u062f \u2014 \u067e\u0648\u0631\u062a\u0627\u0644 Django DRF + React \u0628\u0631\u0627\u06cc \u0645\u062f\u06cc\u0631\u06cc\u062a \u062f\u0631\u062e\u0648\u0627\u0633\u062a \u0648 \u067e\u0630\u06cc\u0631\u0634 \u0627\u0633\u062a\u0639\u062f\u0627\u062f\u0647\u0627\u06cc \u062f\u0631\u062e\u0634\u0627\u0646 \u06a9\u0627\u0631\u0634\u0646\u0627\u0633\u06cc \u0627\u0631\u0634\u062f \u0648 \u062f\u06a9\u062a\u0631\u06cc.")
