B.MN=new A.z(1,0.48627450980392156,0.22745098039215686,0.9294117647058824,B.i)
B.Rq=new A.a_("A full-stack web application developed as a master's degree thesis project. The platform manages application requests and admissions for gifted and outstanding students (\u0627\u0633\u062a\u0639\u062f\u0627\u062f\u0647\u0627\u06cc \u062f\u0631\u062e\u0634\u0627\u0646) applying to MSc and PhD programs. Built with Django REST Framework on the backend and React on the frontend, it implements role-based access control across multiple user levels and secures all API endpoints with JWT authentication.","\u0627\u067e full-stack \u0628\u0647 \u0639\u0646\u0648\u0627\u0646 \u067e\u0631\u0648\u0698\u0647 \u06a9\u0627\u0631\u0634\u0646\u0627\u0633\u06cc \u0627\u0631\u0634\u062f. \u067e\u0644\u062a\u0641\u0631\u0645 \u0645\u062f\u06cc\u0631\u06cc\u062a \u062f\u0631\u062e\u0648\u0627\u0633\u062a\u200c\u0647\u0627 \u0648 \u067e\u0630\u06cc\u0631\u0634 \u062f\u0627\u0646\u0634\u062c\u0648\u06cc\u0627\u0646 \u0627\u0633\u062a\u0639\u062f\u0627\u062f\u0647\u0627\u06cc \u062f\u0631\u062e\u0634\u0627\u0646 \u062f\u0631 \u0645\u0642\u0627\u0637\u0639 \u06a9\u0627\u0631\u0634\u0646\u0627\u0633\u06cc \u0627\u0631\u0634\u062f \u0648 \u062f\u06a9\u062a\u0631\u06cc. \u0628\u06a9\u200c\u0627\u0646\u062f Django REST Framework \u0648 \u0641\u0631\u0627\u0646\u062a React\u060c \u06a9\u0646\u062a\u0631\u0644 \u062f\u0633\u062a\u0631\u0633\u06cc \u0646\u0642\u0634\u200c\u0645\u062d\u0648\u0631 \u062f\u0631 \u0633\u0637\u0648\u062d \u0645\u062e\u062a\u0644\u0641 \u06a9\u0627\u0631\u0628\u0631 \u0648 \u0627\u0645\u0646\u06cc\u062a API \u0628\u0627 JWT.")
B.SM=new A.a_("The gifted student admission process involved paper forms, manual review chains, and no centralized system for applicants, reviewers, and administrators across MSc and PhD tracks.","\u0641\u0631\u0622\u06cc\u0646\u062f \u067e\u0630\u06cc\u0631\u0634 \u0627\u0633\u062a\u0639\u062f\u0627\u062f\u0647\u0627\u06cc \u062f\u0631\u062e\u0634\u0627\u0646 \u0634\u0627\u0645\u0644 \u0641\u0631\u0645 \u06a9\u0627\u063a\u0630\u06cc\u060c \u0632\u0646\u062c\u06cc\u0631\u0647 \u0628\u0631\u0631\u0633\u06cc \u062f\u0633\u062a\u06cc \u0648 \u0646\u0628\u0648\u062f \u0633\u0627\u0645\u0627\u0646\u0647 \u0645\u062a\u0645\u0631\u06a9\u0632 \u0628\u0631\u0627\u06cc \u0645\u062a\u0642\u0627\u0636\u06cc\u060c \u062f\u0627\u0648\u0631 \u0648 \u0645\u062f\u06cc\u0631 \u062f\u0631 \u0645\u0642\u0627\u0637\u0639 \u0627\u0631\u0634\u062f \u0648 \u062f\u06a9\u062a\u0631\u06cc \u0628\u0648\u062f.")
B.SL=new A.a_("Designed and built with Django DRF + React \u2014 multi-role access levels (applicant, reviewer, admin), JWT-secured REST APIs, application submission and tracking workflows, admission decision management, and a modern SPA frontend for a smooth user experience.","\u0637\u0631\u0627\u062d\u06cc \u0648 \u0633\u0627\u062e\u062a \u0628\u0627 Django DRF + React \u2014 \u0633\u0637\u0648\u062d \u062f\u0633\u062a\u0631\u0633\u06cc \u0686\u0646\u062f\u0646\u0642\u0634\u06cc (\u0645\u062a\u0642\u0627\u0636\u06cc\u060c \u062f\u0627\u0648\u0631\u060c \u0645\u062f\u06cc\u0631)\u060c REST API \u0627\u0645\u0646 \u0628\u0627 JWT\u060c \u06af\u0631\u062f\u0634 \u062b\u0628\u062a \u0648 \u067e\u06cc\u06af\u06cc\u0631\u06cc \u062f\u0631\u062e\u0648\u0627\u0633\u062a\u060c \u0645\u062f\u06cc\u0631\u06cc\u062a \u062a\u0635\u0645\u06cc\u0645 \u067e\u0630\u06cc\u0631\u0634 \u0648 SPA \u0645\u062f\u0631\u0646 \u0628\u0631\u0627\u06cc \u062a\u062c\u0631\u0628\u0647 \u06a9\u0627\u0631\u0628\u0631\u06cc \u0631\u0648\u0627\u0646.")
B.RC=new A.a_("A complete thesis deliverable digitizing the gifted student admission pipeline \u2014 secure, role-aware, and ready for university-scale deployment.","\u062a\u062d\u0648\u06cc\u0644 \u06a9\u0627\u0645\u0644 \u067e\u0631\u0648\u0698\u0647 \u067e\u0627\u06cc\u0627\u0646\u200c\u0646\u0627\u0645\u0647 \u2014 \u062f\u06cc\u062c\u06cc\u062a\u0627\u0644\u06cc\u200c\u0633\u0627\u0632\u06cc \u0645\u0633\u06cc\u0631 \u067e\u0630\u06cc\u0631\u0634 \u0627\u0633\u062a\u0639\u062f\u0627\u062f\u0647\u0627\u06cc \u062f\u0631\u062e\u0634\u0627\u0646\u060c \u0627\u0645\u0646\u060c \u0646\u0642\u0634\u200c\u0645\u062d\u0648\u0631 \u0648 \u0622\u0645\u0627\u062f\u0647 \u0627\u0633\u062a\u0642\u0631\u0627\u0631 \u062f\u0631 \u0645\u0642\u06cc\u0627\u0633 \u062f\u0627\u0646\u0634\u06af\u0627\u0647.")
B.Si=new A.a_("Full-Stack Developer (Thesis)","\u062a\u0648\u0633\u0639\u0647\u200c\u062f\u0647\u0646\u062f\u0647 \u0641\u0648\u0644\u200c\u0627\u0633\u062a\u06a9 (\u067e\u0627\u06cc\u0627\u0646\u200c\u0646\u0627\u0645\u0647)")
B.RS=new A.a_("Master's thesis","\u06a9\u0627\u0631\u0634\u0646\u0627\u0633\u06cc \u0627\u0631\u0634\u062f")
