B.Rv=new A.a_("YOLO License Plate Detection","\u062a\u0634\u062e\u06cc\u0635 \u067e\u0644\u0627\u06a9 \u062e\u0648\u062f\u0631\u0648 \u0628\u0627 YOLO")
B.RM=new A.a_("Custom YOLO model training for automatic license plate detection in images and video streams.","\u0622\u0645\u0648\u0632\u0634 \u0645\u062f\u0644 YOLO \u0633\u0641\u0627\u0631\u0634\u06cc \u0628\u0631\u0627\u06cc \u062a\u0634\u062e\u06cc\u0635 \u062e\u0648\u062f\u06a9\u0627\u0631 \u067e\u0644\u0627\u06a9 \u062e\u0648\u062f\u0631\u0648 \u062f\u0631 \u062a\u0635\u0648\u06cc\u0631 \u0648 \u0648\u06cc\u062f\u06cc\u0648.")
B.RN=new A.a_("Computer Vision / ML","\u0628\u06cc\u0646\u0627\u06cc\u06cc \u0645\u0627\u0634\u06cc\u0646 / ML")
B.YN=s(["YOLO","Python","OpenCV","PyTorch"],t.s)
B.o5=new A.z(1,0.9372549019607843,0.26666666666666666,0.26666666666666666,B.i)
B.QT=new A.a_("A computer vision project focused on training a YOLO object detection model to identify and localize vehicle license plates. The workflow covers dataset preparation and labeling, model training and hyperparameter tuning, evaluation with precision/recall metrics, and inference on real-world images and video frames \u2014 enabling automated plate detection for traffic, parking, or security use cases.","\u067e\u0631\u0648\u0698\u0647 \u0628\u06cc\u0646\u0627\u06cc\u06cc \u0645\u0627\u0634\u06cc\u0646 \u0628\u0631\u0627\u06cc \u0622\u0645\u0648\u0632\u0634 \u0645\u062f\u0644 \u062a\u0634\u062e\u06cc\u0635 \u0634\u06cc\u0621 YOLO \u062c\u0647\u062a \u0634\u0646\u0627\u0633\u0627\u06cc\u06cc \u0648 \u0645\u0648\u0642\u0639\u06cc\u062a\u200c\u06cc\u0627\u0628\u06cc \u067e\u0644\u0627\u06a9 \u062e\u0648\u062f\u0631\u0648. \u0634\u0627\u0645\u0644 \u0622\u0645\u0627\u062f\u0647\u200c\u0633\u0627\u0632\u06cc \u0648 label \u062f\u06cc\u062a\u0627\u0633\u062a\u060c \u0622\u0645\u0648\u0632\u0634 \u0645\u062f\u0644 \u0648 tuning\u060c \u0627\u0631\u0632\u06cc\u0627\u0628\u06cc \u0628\u0627 precision/recall \u0648 inference \u0631\u0648\u06cc \u062a\u0635\u0648\u06cc\u0631 \u0648 \u0641\u0631\u06cc\u0645 \u0648\u06cc\u062f\u06cc\u0648 \u2014 \u0628\u0631\u0627\u06cc \u06a9\u0627\u0631\u0628\u0631\u062f \u062a\u0631\u0627\u0641\u06cc\u06a9\u060c \u067e\u0627\u0631\u06a9\u06cc\u0646\u06af \u06cc\u0627 \u0627\u0645\u0646\u06cc\u062a.")
B.QW=new A.a_("Manual license plate reading does not scale for high-volume traffic monitoring \u2014 a reliable automated detector was needed that works across varied lighting, angles, and plate formats.","\u062e\u0648\u0627\u0646\u062f\u0646 \u062f\u0633\u062a\u06cc \u067e\u0644\u0627\u06a9 \u0628\u0631\u0627\u06cc \u067e\u0627\u06cc\u0634 \u067e\u0631\u062a\u0631\u0627\u0641\u06cc\u06a9 \u0645\u0642\u06cc\u0627\u0633\u200c\u067e\u0630\u06cc\u0631 \u0646\u06cc\u0633\u062a \u2014 \u0628\u0647 detector \u062e\u0648\u062f\u06a9\u0627\u0631 \u067e\u0627\u06cc\u062f\u0627\u0631 \u0646\u06cc\u0627\u0632 \u0628\u0648\u062f \u06a9\u0647 \u062f\u0631 \u0646\u0648\u0631\u060c \u0632\u0627\u0648\u06cc\u0647 \u0648 \u0641\u0631\u0645\u062a \u067e\u0644\u0627\u06a9 \u0645\u062e\u062a\u0644\u0641 \u06a9\u0627\u0631 \u06a9\u0646\u062f.")
B.Rc=new A.a_("Prepared a labeled dataset of vehicle images, trained a YOLO model with iterative fine-tuning, validated detection accuracy on held-out samples, and deployed inference pipeline using Python, OpenCV, and PyTorch/Ultralytics stack.","\u062f\u06cc\u062a\u0627\u0633\u062a label\u200c\u0634\u062f\u0647 \u062a\u0635\u0627\u0648\u06cc\u0631 \u062e\u0648\u062f\u0631\u0648\u060c \u0622\u0645\u0648\u0632\u0634 YOLO \u0628\u0627 fine-tuning \u062a\u06a9\u0631\u0627\u0631\u06cc\u060c \u0627\u0639\u062a\u0628\u0627\u0631\u0633\u0646\u062c\u06cc \u062f\u0642\u062a \u0631\u0648\u06cc \u0646\u0645\u0648\u0646\u0647\u200c\u0647\u0627\u06cc test \u0648 pipeline inference \u0628\u0627 Python\u060c OpenCV \u0648 PyTorch/Ultralytics.")
B.Rx=new A.a_("A production-ready plate detection model capable of real-time inference \u2014 foundation for ANPR, parking systems, or traffic analytics pipelines.","\u0645\u062f\u0644 \u062a\u0634\u062e\u06cc\u0635 \u067e\u0644\u0627\u06a9 \u0622\u0645\u0627\u062f\u0647 inference \u0644\u062d\u0638\u0647\u200c\u0627\u06cc \u2014 \u067e\u0627\u06cc\u0647 \u0628\u0631\u0627\u06cc ANPR\u060c \u0633\u06cc\u0633\u062a\u0645 \u067e\u0627\u0631\u06a9\u06cc\u0646\u06af \u06cc\u0627 pipeline \u062a\u062d\u0644\u06cc\u0644 \u062a\u0631\u0627\u0641\u06cc\u06a9.")
B.S6=new A.a_("ML Engineer","\u0645\u0647\u0646\u062f\u0633 \u06cc\u0627\u062f\u06af\u06cc\u0631\u06cc \u0645\u0627\u0634\u06cc\u0646")
B.QS=new A.a_("Research project","\u067e\u0631\u0648\u0698\u0647 \u062a\u062d\u0642\u06cc\u0642\u0627\u062a\u06cc")
B.a6X=new A.di("yolo-license-plate",B.Rv,B.RM,B.RN,B.YN,B.o5,"",B.QT,B.QW,B.Rc,B.Rx,B.S6,B.QS,"assets/images/projects/plate_detection1.jpg",B.bY,!1)
B.Sk=new A.a_("Jet Printer Excel & Scan Verification","\u0686\u0627\u067e Jet Printer \u0627\u0632 Excel \u0648 \u062a\u0623\u06cc\u06cc\u062f \u0628\u0627 \u0627\u0633\u06a9\u0646\u0631")
B.S1=new A.a_("Flutter desktop app \u2014 reads Excel files, sends print commands to industrial Jet Printers, and verifies output with a barcode scanner.","\u0627\u067e \u062f\u0633\u06a9\u062a\u0627\u067e Flutter \u2014 \u062e\u0648\u0627\u0646\u062f\u0646 \u0641\u0627\u06cc\u0644 Excel\u060c \u0627\u0631\u0633\u0627\u0644 \u062f\u0633\u062a\u0648\u0631 \u0686\u0627\u067e \u0628\u0647 Jet Printer \u0635\u0646\u0639\u062a\u06cc \u0648 \u0628\u0631\u0631\u0633\u06cc \u0635\u062d\u062a \u0686\u0627\u067e \u0628\u0627 \u0627\u0633\u06a9\u0646\u0631 \u0628\u0627\u0631\u06a9\u062f.")
B.pC=new A.a_("Industrial Desktop App","\u0627\u067e \u062f\u0633\u06a9\u062a\u0627\u067e \u0635\u0646\u0639\u062a\u06cc")
B.X4=s(["Flutter","Excel","Jet Printer","Barcode Scanner"],t.s)
B.Mn=new A.z(1,0.0784313725490196,0.7215686274509804,0.6509803921568628,B.i)
B.Sq=new A.a_("A Flutter desktop application for production-line labeling workflows. Operators upload Excel files containing product data; the app parses rows and sends formatted print jobs to industrial Jet Printers. After printing, a barcode scanner verifies that the label was applied correctly \u2014 closing the loop between data import, print execution, and quality control.","\u0627\u067e \u062f\u0633\u06a9\u062a\u0627\u067e Flutter \u0628\u0631\u0627\u06cc \u06af\u0631\u062f\u0634 \u06a9\u0627\u0631 \u0644\u06cc\u0628\u0644\u200c\u06af\u0630\u0627\u0631\u06cc \u062e\u0637 \u062a\u0648\u0644\u06cc\u062f. \u0627\u067e\u0631\u0627\u062a\u0648\u0631 \u0641\u0627\u06cc\u0644 Excel \u062d\u0627\u0648\u06cc \u062f\u0627\u062f\u0647 \u0645\u062d\u0635\u0648\u0644 \u0631\u0627 \u0628\u0627\u0631\u06af\u0630\u0627\u0631\u06cc \u0645\u06cc\u200c\u06a9\u0646\u062f\u061b \u0627\u067e \u0633\u0637\u0631\u0647\u0627 \u0631\u0627 parse \u0648 \u062f\u0633\u062a\u0648\u0631 \u0686\u0627\u067e \u0641\u0631\u0645\u062a\u200c\u0634\u062f\u0647 \u0628\u0647 Jet Printer \u0635\u0646\u0639\u062a\u06cc \u0645\u06cc\u200c\u0641\u0631\u0633\u062a\u062f. \u067e\u0633 \u0627\u0632 \u0686\u0627\u067e\u060c \u0627\u0633\u06a9\u0646\u0631 \u0628\u0627\u0631\u06a9\u062f \u0635\u062d\u062a \u0627\u0639\u0645\u0627\u0644 \u0644\u06cc\u0628\u0644 \u0631\u0627 \u0628\u0631\u0631\u0633\u06cc \u0645\u06cc\u200c\u06a9\u0646\u062f \u2014 \u0628\u0633\u062a\u0646 \u062d\u0644\u0642\u0647 \u0628\u06cc\u0646 import \u062f\u0627\u062f\u0647\u060c \u0627\u062c\u0631\u0627\u06cc \u0686\u0627\u067e \u0648 \u06a9\u0646\u062a\u0631\u0644 \u06a9\u06cc\u0641\u06cc\u062a.")
B.Sc=new A.a_("Manual label printing from spreadsheets caused misprints, no verification step, and slow handoff between office data and the production floor.","\u0686\u0627\u067e \u062f\u0633\u062a\u06cc \u0644\u06cc\u0628\u0644 \u0627\u0632 Excel \u0628\u0627\u0639\u062b \u0686\u0627\u067e \u0627\u0634\u062a\u0628\u0627\u0647\u060c \u0646\u0628\u0648\u062f \u0645\u0631\u062d\u0644\u0647 \u062a\u0623\u06cc\u06cc\u062f \u0648 \u0627\u0646\u062a\u0642\u0627\u0644 \u06a9\u0646\u062f \u062f\u0627\u062f\u0647 \u0628\u06cc\u0646 \u062f\u0641\u062a\u0631 \u0648 \u062e\u0637 \u062a\u0648\u0644\u06cc\u062f \u0645\u06cc\u200c\u0634\u062f.")
B.R8=new A.a_("Built with Flutter \u2014 Excel parsing and batch queue management, Jet Printer driver integration for industrial print commands, scanner input for post-print barcode verification, and operator-friendly UI for daily production use.","\u0628\u0627 Flutter \u2014 parse \u0648 \u0635\u0641 Excel\u060c \u0627\u062a\u0635\u0627\u0644 Jet Printer \u0628\u0631\u0627\u06cc \u062f\u0633\u062a\u0648\u0631 \u0686\u0627\u067e \u0635\u0646\u0639\u062a\u06cc\u060c \u0648\u0631\u0648\u062f\u06cc \u0627\u0633\u06a9\u0646\u0631 \u0628\u0631\u0627\u06cc \u062a\u0623\u06cc\u06cc\u062f \u0628\u0627\u0631\u06a9\u062f \u067e\u0633 \u0627\u0632 \u0686\u0627\u067e\u060c \u0648 UI \u0645\u0646\u0627\u0633\u0628 \u0627\u067e\u0631\u0627\u062a\u0648\u0631 \u0628\u0631\u0627\u06cc \u0627\u0633\u062a\u0641\u0627\u062f\u0647 \u0631\u0648\u0632\u0627\u0646\u0647 \u062a\u0648\u0644\u06cc\u062f.")
B.RT=new A.a_("Automated Excel-to-printer pipeline, reduced labeling errors, and verified print quality on every unit before it leaves the line.","\u062e\u0637 \u0644\u0648\u0644\u0647 \u062e\u0648\u062f\u06a9\u0627\u0631 Excel \u062a\u0627 \u067e\u0631\u06cc\u0646\u062a\u0631\u060c \u06a9\u0627\u0647\u0634 \u062e\u0637\u0627\u06cc \u0644\u06cc\u0628\u0644 \u0648 \u062a\u0623\u06cc\u06cc\u062f \u06a9\u06cc\u0641\u06cc\u062a \u0686\u0627\u067e \u0631\u0648\u06cc \u0647\u0631 \u0648\u0627\u062d\u062f \u0642\u0628\u0644 \u0627\u0632 \u062e\u0631\u0648\u062c \u0627\u0632 \u062e\u0637.")
