B.Sy=new A.a_("Barcode-Triggered Label Printer","\u0686\u0627\u067e \u0644\u06cc\u0628\u0644 \u0628\u0627 \u0645\u062d\u0631\u06a9 \u0628\u0627\u0631\u06a9\u062f")
B.Sg=new A.a_("Python PySide desktop app \u2014 barcode scanner reads a code and the system sends user-configured label data to a printer.","\u0627\u067e \u062f\u0633\u06a9\u062a\u0627\u067e Python PySide \u2014 \u0627\u0633\u06a9\u0646\u0631 \u0628\u0627\u0631\u06a9\u062f \u0631\u0627 \u0645\u06cc\u200c\u062e\u0648\u0627\u0646\u062f \u0648 \u0633\u06cc\u0633\u062a\u0645 \u0627\u0637\u0644\u0627\u0639\u0627\u062a \u0627\u0632 \u067e\u06cc\u0634 \u062a\u0639\u06cc\u06cc\u0646\u200c\u0634\u062f\u0647 \u06a9\u0627\u0631\u0628\u0631 \u0631\u0627 \u0628\u0647 \u067e\u0631\u06cc\u0646\u062a\u0631 \u0627\u0631\u0633\u0627\u0644 \u0645\u06cc\u200c\u06a9\u0646\u062f.")
