B.RE=new A.a_("A lightweight Python desktop utility built with PySide for warehouse and production environments. A barcode scanner reads product or batch codes; based on mappings the user configures in advance, the system automatically formats and sends the corresponding label content to a connected printer \u2014 no manual copy-paste between systems.","\u0627\u0628\u0632\u0627\u0631 \u062f\u0633\u06a9\u062a\u0627\u067e \u0633\u0628\u06a9 Python \u0628\u0627 PySide \u0628\u0631\u0627\u06cc \u0627\u0646\u0628\u0627\u0631 \u0648 \u062a\u0648\u0644\u06cc\u062f. \u0627\u0633\u06a9\u0646\u0631 \u0628\u0627\u0631\u06a9\u062f \u06a9\u062f \u0645\u062d\u0635\u0648\u0644 \u06cc\u0627 batch \u0631\u0627 \u0645\u06cc\u200c\u062e\u0648\u0627\u0646\u062f\u061b \u0628\u0631 \u0627\u0633\u0627\u0633 mapping \u0627\u0632 \u067e\u06cc\u0634 \u062a\u0639\u0631\u06cc\u0641\u200c\u0634\u062f\u0647 \u062a\u0648\u0633\u0637 \u06a9\u0627\u0631\u0628\u0631\u060c \u0633\u06cc\u0633\u062a\u0645 \u062e\u0648\u062f\u06a9\u0627\u0631 \u0645\u062d\u062a\u0648\u0627\u06cc \u0644\u06cc\u0628\u0644 \u0631\u0627 \u0641\u0631\u0645\u062a \u0648 \u0628\u0647 \u067e\u0631\u06cc\u0646\u062a\u0631 \u0645\u062a\u0635\u0644 \u0627\u0631\u0633\u0627\u0644 \u0645\u06cc\u200c\u06a9\u0646\u062f \u2014 \u0628\u062f\u0648\u0646 copy-paste \u062f\u0633\u062a\u06cc \u0628\u06cc\u0646 \u0633\u06cc\u0633\u062a\u0645\u200c\u0647\u0627.")
B.Ra=new A.a_("Operators had to look up barcode values manually and re-enter label text for every scan \u2014 slow, error-prone, and unsuitable for high-volume labeling.","\u0627\u067e\u0631\u0627\u062a\u0648\u0631\u0647\u0627 \u0628\u0627\u06cc\u062f \u0645\u0642\u062f\u0627\u0631 \u0628\u0627\u0631\u06a9\u062f \u0631\u0627 \u062f\u0633\u062a\u06cc \u067e\u06cc\u062f\u0627 \u0648 \u0645\u062a\u0646 \u0644\u06cc\u0628\u0644 \u0631\u0627 \u0628\u0631\u0627\u06cc \u0647\u0631 \u0627\u0633\u06a9\u0646 \u062f\u0648\u0628\u0627\u0631\u0647 \u0648\u0627\u0631\u062f \u0645\u06cc\u200c\u06a9\u0631\u062f\u0646\u062f \u2014 \u06a9\u0646\u062f\u060c \u062e\u0637\u0627\u067e\u0630\u06cc\u0631 \u0648 \u0646\u0627\u0645\u0646\u0627\u0633\u0628 \u0628\u0631\u0627\u06cc \u062d\u062c\u0645 \u0628\u0627\u0644\u0627\u06cc \u0644\u06cc\u0628\u0644\u200c\u06af\u0630\u0627\u0631\u06cc.")
B.Rb=new A.a_("Built with Python and PySide \u2014 configurable barcode-to-label mapping table, real-time scanner input handling, print template engine, and direct printer dispatch so each scan triggers the correct label instantly.","\u0628\u0627 Python \u0648 PySide \u2014 \u062c\u062f\u0648\u0644 mapping \u0628\u0627\u0631\u06a9\u062f \u0628\u0647 \u0644\u06cc\u0628\u0644 \u0642\u0627\u0628\u0644 \u062a\u0646\u0638\u06cc\u0645\u060c \u067e\u0631\u062f\u0627\u0632\u0634 \u0644\u062d\u0638\u0647\u200c\u0627\u06cc \u0648\u0631\u0648\u062f\u06cc \u0627\u0633\u06a9\u0646\u0631\u060c \u0645\u0648\u062a\u0648\u0631 template \u0686\u0627\u067e \u0648 \u0627\u0631\u0633\u0627\u0644 \u0645\u0633\u062a\u0642\u06cc\u0645 \u0628\u0647 \u067e\u0631\u06cc\u0646\u062a\u0631 \u062a\u0627 \u0647\u0631 \u0627\u0633\u06a9\u0646 \u0641\u0648\u0631\u0627\u064b \u0644\u06cc\u0628\u0644 \u062f\u0631\u0633\u062a \u0631\u0627 \u0686\u0627\u067e \u06a9\u0646\u062f.")
